const input = $json ?? {};
const binary = $binary ?? {};

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function extractGoogleDriveFileId(value) {
  const text = safeText(value);
  if (!text) return '';

  const patterns = [
    /\/d\/([a-zA-Z0-9_-]{10,})/i,
    /[?&]id=([a-zA-Z0-9_-]{10,})/i,
    /^([a-zA-Z0-9_-]{10,})$/,
  ];

  for (const pattern of patterns) {
    const match = text.match(pattern);
    if (match?.[1]) return match[1];
  }

  return '';
}

const supportedAction = ['upsert', 'get', 'delete', 'list']
const action = safeText(input.action).toLowerCase() || 'upsert';
if (!supportedAction.includes(action)) {
  throw new Error('Unsupported action: ' + action + '. Allowed: ' + supportedAction.join('|'));
}

const rootFolderId = safeText(input.rootFolderId) || 'root';
const normalizedPath = safeText(input.folderPath)
  .replace(/^\/+|\/+$/g, '')
  .replace(/\/+/g, '/');

const segments = normalizedPath ? normalizedPath.split('/').filter(Boolean) : [];
const currentSegment = segments[0] || '';
const remainingPath = segments.length > 1 ? segments.slice(1).join('/') : '';

const explicitBinaryField = safeText(input.binaryFieldName);
const availableBinaryFields = Object.keys(binary);
const binaryFieldName = explicitBinaryField && binary[explicitBinaryField]
  ? explicitBinaryField
  : (availableBinaryFields[0] || '');

const binaryFile = binaryFieldName ? binary[binaryFieldName] : null;
const fileName = safeText(input.fileName, safeText(binaryFile?.fileName, 'uploaded-file.bin'));

const rawFileUrl = safeText(input.url);
const fileId = extractGoogleDriveFileId(rawFileUrl);
const fileUrl = rawFileUrl || (fileId ? 'https://drive.google.com/file/d/' + fileId + '/view' : '');

return [{
  json: {
    ...input,
    action,
    rootFolderId,
    folderPath: normalizedPath,
    currentSegment,
    remainingPath,
    baseFolderId: rootFolderId,
    binaryFieldName,
    hasBinaryFile: Boolean(binaryFile),
    fileName,
    fileId,
    fileUrl,
  },
  binary,
}];

const input = $json ?? {};
const binary = $binary ?? {};

// 1. Kiểm tra xem node trước đó có trả về lỗi không
// n8n thường để lỗi trong trường 'error' hoặc dựa trên status code
const isError = !!(input.error || input.message && input.code);

if (isError) {
  return {
    json: {
      status: 'error',
      action: $('Normalize Request').first().json.action,
      errorCode: input.code || input.statusCode || 'UNKNOWN_ERROR',
      errorMessage: input.message || (input.error ? JSON.stringify(input.error) : 'No error message provided'),
      fileId: String(input.id || input.fileId || '').trim(), // Cố gắng lấy ID nếu có
    }
  };
}

// 2. Logic xử lý khi THÀNH CÔNG (Giữ nguyên của bạn và tối ưu nhẹ)
const binaryKeys = Object.keys(binary);
const binaryKey = binaryKeys[0] || 'file';
const binaryFile = binary[binaryKey] || {};

const fileId = String(input.id || input.fileId || '').trim();
const fileUrl = String(
  input.webViewLink || 
  input.fileUrl || 
  (fileId ? `https://drive.google.com/file/d/${fileId}/view` : '')
).trim();

const parentFolderId = Array.isArray(input.parents) && input.parents.length > 0
  ? String(input.parents[0] || '').trim()
  : '';

const parentFolderUrl = parentFolderId 
  ? `https://drive.google.com/drive/folders/${parentFolderId}` 
  : '';

return {
  json: {
    status: 'success',
    action: $('Normalize Request').first().json.action,
    fileId,
    fileName: String(binaryFile.fileName || input.name || input.fileName || '').trim(),
    fileUrl,
    folderId: parentFolderId,
    folderUrl: parentFolderUrl,
    binaryFieldName: binaryKey,
  },
  binary,
};

const currentJson = $json ?? {};
const currentBinary = $binary ?? {};

const ifHasBinaryItem = $('If Has File Binary').first() ?? {};
const ifHasBinaryJson = ifHasBinaryItem.json ?? {};
const ifHasBinaryBinary = ifHasBinaryItem.binary ?? {};

const normalizeItem = $('Normalize Request').first() ?? {};
const normalizeJson = normalizeItem.json ?? {};
const normalizeBinary = normalizeItem.binary ?? {};

const pickBinary = (...candidates) => {
  for (const candidate of candidates) {
    if (candidate && Object.keys(candidate).length > 0) {
      return candidate;
    }
  }
  return {};
};

const outputBinary = pickBinary(currentBinary, ifHasBinaryBinary, normalizeBinary);
const binaryKeys = Object.keys(outputBinary);

const requestedBinaryField = String(
  currentJson.binaryFieldName || ifHasBinaryJson.binaryFieldName || normalizeJson.binaryFieldName || ''
).trim();

const binaryFieldName = requestedBinaryField && outputBinary[requestedBinaryField]
  ? requestedBinaryField
  : (binaryKeys[0] || requestedBinaryField || '');

return {
  json: {
    ...normalizeJson,
    ...ifHasBinaryJson,
    ...currentJson,
    binaryFieldName,
    hasBinaryFile: binaryKeys.length > 0,
  },
  binary: outputBinary,
};

const context = $('Finalize Target Context').first().json || {};
const inputItems = $input.all();

const toFileUrl = (row) => {
  const id = String(row.id || '');
  if (!id) return '';
  const mimeType = String(row.mimeType || '');
  if (mimeType === 'application/vnd.google-apps.folder') {
    return row.webViewLink || ('https://drive.google.com/drive/folders/' + id);
  }
  return row.webViewLink || ('https://drive.google.com/file/d/' + id + '/view');
};

const items = inputItems
  .map((entry) => entry.json || {})
  .filter((row) => String(row.id || '').trim().length > 0)
  .map((row) => ({
    id: String(row.id || ''),
    name: String(row.name || ''),
    mimeType: String(row.mimeType || ''),
    size: String(row.size || ''),
    webViewLink: String(row.webViewLink || ''),
    url: toFileUrl(row),
    isFolder: String(row.mimeType || '') === 'application/vnd.google-apps.folder'
  }));

return [{
  json: {
    status: 'success',
    action: 'list',
    folderId: String(context.targetFolderId || ''),
    folderUrl: String(context.targetFolderUrl || ('https://drive.google.com/drive/folders/' + (context.targetFolderId || ''))),
    itemCount: items.length,
    items
  }
}];

const base = $('If Has Segment').item?.json ?? {};
const current = $json ?? {};

return {
  json: {
    ...base,
    ...current,
  },
  binary: $binary,
};

const input = $json ?? {};

// 1. Nhận diện lỗi từ node Delete trước đó
// Thường node Delete lỗi sẽ trả về 'message' và 'code' (ví dụ 404, 403)
const isError = !!(input.error || (input.message && input.code));
const isFolder = $('Get Drive Info').first().json.isFolder || false;

if (isError) {
  return {
    json: {
      status: 'error',
      action: $input.first().json.id,
      id: String(input.id || '').trim(),
      url: $('Normalize Request').first().json.url,
      errorCode: input.code || input.statusCode || 'UNKNOWN_ERROR',
      errorMessage: input.message || 'Không thể xóa file/folder này.',
      isFolder,
    }
  };
}

// 2. Logic khi THÀNH CÔNG
// Lưu ý: Google Drive Delete thường trả về object rỗng hoặc chỉ có ID
// Nếu node trước không trả về ID, ta lấy từ node cha (nếu có)

return {
  json: {
    status: 'success',
    action: 'delete',
    id: String(input.id || '').trim(),
    url: $('Normalize Request').first().json.url,
    message: 'Đã xóa ' + (isFolder ? 'folder' : 'file') + ' thành công.',
    isFolder,
  }
};

const input = $json ?? {};

function safeText(value, fallback = '') {
  return String(value ?? '').trim() || fallback;
}

function getDriveInfo(value) {
  const text = safeText(value);
  if (!text) return { id: '', isFolder: false };

  // Thứ tự ưu tiên: Check folder trước vì patterns khá đặc thù
  const folderMatch = text.match(/\/folders\/([a-zA-Z0-9_-]{25,})/i);
  if (folderMatch) return { id: folderMatch[1], isFolder: true };

  // Check các dạng file còn lại
  const filePatterns = [
    /\/d\/([a-zA-Z0-9_-]{25,})/i,
    /[?&]id=([a-zA-Z0-9_-]{25,})/i,
    /^([a-zA-Z0-9_-]{25,})$/
  ];

  for (const pattern of filePatterns) {
    const match = text.match(pattern);
    if (match?.[1]) return { id: match[1], isFolder: false };
  }

  return { id: '', isFolder: false };
}

const result = getDriveInfo(input.url);

return { 
  id: result.id, 
  isFolder: result.isFolder,
  found: !!result.id // Thêm cái này để node IF sau này check cho dễ
};
